const submitHandler = async (e) => {
  e.preventDefault();

  try {
    await API.post("/tasks", {
      title,
      description,
      status: "Pending",
    });

    setTitle("");
    setDescription("");

    fetchTasks();

    alert("Task Added Successfully!");
  } catch (error) {
    alert("Error adding task");
  }
};
